// getBody returns the best available plain-text body from a MIME message.
func getBody(msg *message.Entity) (string, error) {
	mr := msg.MultipartReader()
	if mr != nil {
		// Prefer text/plain; fall back to text/html
		for _, preferredType := range []string{"text/plain", "text/html"} {
			parts, err := collectParts(mr)
			if err != nil {
				return "", fmt.Errorf("multipart walk error: %w", err)
			}
			for _, part := range parts {
				ct, _, _ := mime.ParseMediaType(part.Header.Get("Content-Type"))
				if ct != preferredType {
					continue
				}
				disp := part.Header.Get("Content-Disposition")
				if strings.Contains(disp, "attachment") {
					continue
				}
				body, err := io.ReadAll(part.Body)
				if err != nil || len(body) == 0 {
					continue
				}
				if preferredType == "text/html" {
					return htmlExtractorExtract(body)
				}
				return string(body), nil
			}
		}
		return "", nil
	}
	// Non-multipart
	body, err := io.ReadAll(msg.Body)
	if err != nil {
		return "", fmt.Errorf("body read error: %w", err)
	}
	if len(body) == 0 {
		return "", nil
	}
	ct, _, _ := mime.ParseMediaType(msg.Header.Get("Content-Type"))
	if ct == "text/html" {
		return htmlExtractorExtract(body)
	}
	return string(body), nil
}

// extractAttachments returns extracted text blocks from each MIME attachment.
func extractAttachments(msg *message.Entity) ([]string, error) {
	blocks := []string{}
	parts, err := collectParts(msg.MultipartReader())
	if err != nil {
		return nil, fmt.Errorf("attachment walk error: %w", err)
	}
	for _, part := range parts {
		disp := part.Header.Get("Content-Disposition")
		_, dispParams, _ := mime.ParseMediaType(disp)
		filename := dispParams["filename"]
		if filename == "" && !strings.Contains(disp, "attachment") {
			continue
		}
		body, readErr := io.ReadAll(part.Body)
		if readErr != nil || len(body) == 0 {
			continue
		}
		if filename == "" {
			filename = "attachment"
		}
		ct, _, _ := mime.ParseMediaType(part.Header.Get("Content-Type"))
		docType := detectTypeFromSource(filename, ct)
		extractor, extErr := detectExtractor(docType)
		if extErr != nil {
			log.Printf("EmailExtractor: skipping attachment %s: %v", filename, extErr)
			continue
		}
		text, extErr := extractor.Extract(body, filename)
		if extErr != nil {
			log.Printf("EmailExtractor: skipping attachment %s: %v", filename, extErr)
			continue
		}
		if strings.TrimSpace(text) != "" {
			blocks = append(blocks, fmt.Sprintf("[Attachment: %s]\n%s", filename, strings.TrimSpace(text)))
		}
	}
	return blocks, nil
}

