// iterLabels extracts the list of label dicts from an openFDA API response object.
func iterLabels(obj interface{}) []map[string]interface{} {
	switch v := obj.(type) {
	case map[string]interface{}:
		if results, ok := v["results"]; ok {
			resultSlice, _ := results.([]interface{})
			out := []map[string]interface{}{}
			for _, r := range resultSlice {
				if m, ok := r.(map[string]interface{}); ok {
					out = append(out, m)
				}
			}
			return out
		}
		if _, hasOpenfda := v["openfda"]; hasOpenfda {
			return []map[string]interface{}{v}
		}
		if _, hasIndications := v["indications_and_usage"]; hasIndications {
			return []map[string]interface{}{v}
		}
	case []interface{}:
		out := []map[string]interface{}{}
		for _, r := range v {
			if m, ok := r.(map[string]interface{}); ok {
				out = append(out, m)
			}
		}
		return out
	}
	return []map[string]interface{}{}
}

// labelID returns the application number, set_id, id, or "UNKNOWN" for a label dict.
func labelID(label map[string]interface{}) string {
	openfda, _ := label["openfda"].(map[string]interface{})
	if appl, ok := openfda["application_number"]; ok {
		switch a := appl.(type) {
		case []interface{}:
			if len(a) > 0 {
				if s, ok := a[0].(string); ok {
					return s
				}
			}
		case string:
			if a != "" {
				return a
			}
		}
	}
	if v, _ := label["set_id"].(string); v != "" {
		return v
	}
	if v, _ := label["id"].(string); v != "" {
		return v
	}
	return "UNKNOWN"
}

