// renderPatient renders a FHIR Patient resource as markdown.
func renderPatient(res map[string]interface{}) string {
	rid, _ := res["id"].(string)
	if rid == "" {
		rid = "UNKNOWN"
	}
	nameStr := ""
	if names, ok := res["name"].([]interface{}); ok && len(names) > 0 {
		if n, ok := names[0].(map[string]interface{}); ok {
			givenParts := []string{}
			if given, ok := n["given"].([]interface{}); ok {
				for _, g := range given {
					if s, ok := g.(string); ok {
						givenParts = append(givenParts, s)
					}
				}
			}
			family, _ := n["family"].(string)
			nameStr = strings.TrimSpace(strings.Join(givenParts, " ") + " " + family)
		}
	}

	gender, _ := res["gender"].(string)
	birthDate, _ := res["birthDate"].(string)
	identifiers := []string{}
	if identList, ok := res["identifier"].([]interface{}); ok {
		for _, id := range identList {
			ident, ok := id.(map[string]interface{})
			if !ok {
				continue
			}
			sys, _ := ident["system"].(string)
			val, _ := ident["value"].(string)
			if val != "" {
				if sys != "" {
					identifiers = append(identifiers, fmt.Sprintf("%s (%s)", val, sys))
				} else {
					identifiers = append(identifiers, val)
				}
			}
		}
	}

	lines := []string{fmt.Sprintf("# Patient/%s %s", rid, nameStr), ""}
	if gender != "" {
		lines = append(lines, fmt.Sprintf("**Gender:** %s", gender))
	}
	if birthDate != "" {
		lines = append(lines, fmt.Sprintf("**DOB:** %s", birthDate))
	}
	if len(identifiers) > 0 {
		cap := 3
		if len(identifiers) < cap {
			cap = len(identifiers)
		}
		lines = append(lines, fmt.Sprintf("**Identifiers:** %s", strings.Join(identifiers[:cap], ", ")))
	}
	return strings.Join(lines, "\n")
}

