func renderObservationLines(res map[string]interface{}) []string {
	lines := []string{}
	if val, ok := res["valueQuantity"].(map[string]interface{}); ok {
		v := val["value"]
		unit, _ := val["unit"].(string)
		if unit == "" {
			unit, _ = val["code"].(string)
		}
		if v != nil {
			lines = append(lines, "", strings.TrimSpace(fmt.Sprintf("**Value:** %v %s", v, unit)))
		}
	}
	if valStr, ok := res["valueString"].(string); ok && valStr != "" {
		lines = append(lines, "", fmt.Sprintf("**Value:** %s", valStr))
	}
	componentRaw, _ := res["component"].([]interface{})
	if len(componentRaw) > 0 {
		lines = append(lines, "", "## Components", "")
		limit := 20
		if len(componentRaw) < limit {
			limit = len(componentRaw)
		}
		for _, c := range componentRaw[:limit] {
			comp, ok := c.(map[string]interface{})
			if !ok {
