// headingFrame tracks one level of heading context.
type headingFrame struct {
	Level  int
	Anchor string
	Text   string
}

// sectionAnchor stores the resolved anchor and heading path for one heading.
type sectionAnchor struct {
	Anchor string
	Path   []string
}

// segment stores one markdown segment with its heading context.
type segment struct {
	Anchor string
	Path   []string
	Text   string
