					LineStart: n.Lineno,
					LineEnd:   n.EndLineno,
					Symbol:    n.Name,
				}
			}
		case *FunctionDef:
			sectionMap[n.Name] = sectionInfo{
				LineStart: n.Lineno,
				LineEnd:   n.EndLineno,
				Symbol:    n.Name,
			}
		}
	}

	for _, chunk := range chunks {
		key := strings.Join(chunk.Section, ".")
		if info, ok := sectionMap[key]; ok {
			chunk.SourceDetail = map[string]interface{}{
				"line_start": info.LineStart,
				"line_end":   info.LineEnd,
				"symbol":     info.Symbol,
			}
		}
	}
	return chunks, nil
}
